import type { Point } from '../../../types/point.js';

export interface SelectionState {
  selectionPercentage?: [number, number];
  end: {
    relative: Point;
  };
}

export interface ChartBounds {
  left: number;
  top: number;
  width: number;
  height: number;
}

const TOOLTIP_OFFSET_X = 6;
const TOOLTIP_OFFSET_Y = 12;

/**
 * Calculates the position for the selection area tooltip.
 *
 * @param selectState - The current selection state
 * @param chartBounds - The chart bounds including position and dimensions
 * @returns The absolute position for the tooltip
 */
export const getSelectionTooltipPosition = (
  selectState: SelectionState,
  chartBounds: ChartBounds,
): Point => {
  return {
    x: Math.round(
      TOOLTIP_OFFSET_X +
        chartBounds.left +
        (chartBounds.width *
          (selectState.selectionPercentage
            ? selectState.selectionPercentage[1]
            : 0)) /
          100,
    ),
    y: Math.round(chartBounds.top + chartBounds.height / 2 - TOOLTIP_OFFSET_Y),
  };
};
